mapper.select:
select '' as id ,'TERMS' as reqTp --용어 ,TERMS_ID as reqItemId ,TERMS_NM as reqItemNm ,TERMS_ENG_ABRV_NM as reqItemEngNm ,0 as aprvStat --요청됨 ,CRET_USER_ID as reqUserId ,to_char(to_timestamp(CRET_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as reqCretDt ,to_char(to_timestamp(UPDT_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as reqUpdtDt ,APRV_USER_ID as aprvUserId ,to_char(to_timestamp(APRV_STAT_UPDT_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as aprvStatUpdtDt ,'' as aprvStatUpdtRsn from TB_TERMS where APRV_YN = 'N' AND NOT EXISTS (SELECT 1 FROM TB_APRV_STATS s WHERE s.REQ_ITEM_ID = TERMS_ID AND s.REQ_TP = 'TERMS')
AND CRET_USER_ID = #{reqUserId}
AND 0 in #{item.value}
AND CRET_DT >= #{from}
AND CRET_DT <= #{to}
union all select '' as id ,'WORD' as reqTp --단어 ,WORD_ID as reqItemId ,WORD_NM as reqItemNm ,WORD_ENG_ABRV_NM as reqItemEngNm ,0 as aprvStat --요청됨 ,CRET_USER_ID as reqUserId ,to_char(to_timestamp(CRET_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as reqCretDt ,to_char(to_timestamp(UPDT_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as reqUpdtDt ,APRV_USER_ID as aprvUserId ,to_char(to_timestamp(APRV_STAT_UPDT_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as aprvStatUpdtDt ,'' as aprvStatUpdtRsn from TB_WORD where APRV_YN = 'N' AND NOT EXISTS (SELECT 1 FROM TB_APRV_STATS s WHERE s.REQ_ITEM_ID = WORD_ID AND s.REQ_TP = 'WORD')
AND CRET_USER_ID = #{reqUserId}
AND 0 in #{item.value}
AND CRET_DT >= #{from}
AND CRET_DT <= #{to}
union all select '' as id ,'DOMAIN' as reqTp --도메인 ,DOMAIN_ID as reqItemId ,DOMAIN_NM as reqItemNm ,DOMAIN_NM as reqItemEngNm ,0 as aprvStat --요청됨 ,CRET_USER_ID as reqUserId ,to_char(to_timestamp(CRET_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as reqCretDt ,to_char(to_timestamp(UPDT_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as reqUpdtDt ,APRV_USER_ID as aprvUserId ,to_char(to_timestamp(APRV_STAT_UPDT_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as aprvStatUpdtDt ,'' as aprvStatUpdtRsn from TB_DOMAIN where APRV_YN = 'N' AND NOT EXISTS (SELECT 1 FROM TB_APRV_STATS s WHERE s.REQ_ITEM_ID = DOMAIN_ID AND s.REQ_TP = 'DOMAIN')
AND CRET_USER_ID = #{reqUserId}
AND 0 in #{item.value}
AND CRET_DT >= #{from}
AND CRET_DT <= #{to}
union all select A.REQ_ID as id ,A.REQ_TP as reqTp ,A.REQ_ITEM_ID as reqItemId ,CASE WHEN A.REQ_TP = 'WORD' THEN (select WORD_NM from tb_word where WORD_ID = A.REQ_ITEM_ID) WHEN A.REQ_TP = 'TERMS' THEN (select TERMS_NM from tb_terms where TERMS_ID = A.REQ_ITEM_ID) WHEN A.REQ_TP = 'DOMAIN' THEN (select DOMAIN_NM from tb_domain where DOMAIN_ID = A.REQ_ITEM_ID) ELSE NULL END as reqItemNm ,CASE WHEN A.REQ_TP = 'WORD' THEN (select WORD_ENG_ABRV_NM from tb_word where WORD_ID = A.REQ_ITEM_ID) WHEN A.REQ_TP = 'TERMS' THEN (select TERMS_ENG_ABRV_NM from tb_terms where TERMS_ID = A.REQ_ITEM_ID) WHEN A.REQ_TP = 'DOMAIN' THEN (select DOMAIN_NM from tb_domain where DOMAIN_ID = A.REQ_ITEM_ID) ELSE NULL END as reqItemEngNm ,A.APRV_STAT as aprvStat ,A.REQ_USER_ID as reqUserId ,to_char(to_timestamp(A.REQ_CRET_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as reqCretDt ,to_char(to_timestamp(A.REQ_UPDT_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as reqUpdtDt ,A.APRV_USER_ID as aprvUserId ,to_char(to_timestamp(A.APRV_STAT_UPDT_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as aprvStatUpdtDt ,A.APRV_STAT_UPDT_RSN as aprvStatUpdtRsn from TB_APRV_STATS A inner join ( select REQ_ITEM_ID, REQ_TP, MAX(APRV_STAT_UPDT_DT) as max_dt from TB_APRV_STATS group by REQ_ITEM_ID, REQ_TP ) latest ON A.REQ_ITEM_ID = latest.REQ_ITEM_ID AND A.REQ_TP = latest.REQ_TP AND A.APRV_STAT_UPDT_DT = latest.max_dt where A.REQ_ID is not null
AND REQ_USER_ID = #{reqUserId}
AND APRV_STAT in #{item.value}
AND REQ_CRET_DT >= #{from}
AND REQ_CRET_DT <= #{to}
order by reqCretDt desc, aprvStatUpdtDt desc, reqItemId

mapper.insert:
           INSERT INTO TB_APRV_STATS
           (
             REQ_ID
            ,REQ_TP			
            ,REQ_ITEM_ID
            ,APRV_STAT		
            ,REQ_USER_ID	
            ,REQ_CRET_DT
			      ,REQ_UPDT_DT
            ,APRV_USER_ID	
            ,APRV_STAT_UPDT_DT	
            ,APRV_STAT_UPDT_RSN
           )
           VALUES
           (
             #{id}
            ,#{reqTp}
            ,#{reqItemId}
            ,#{aprvStat}
            ,#{reqUserId, jdbcType=VARCHAR}
            ,#{reqCretDt, jdbcType=VARCHAR}
			      ,#{reqUpdtDt, jdbcType=VARCHAR}
            ,#{aprvUserId, jdbcType=VARCHAR}
            ,to_char(now(), 'YYYYMMDDHH24MISS')
            ,#{aprvStatUpdtRsn, jdbcType=VARCHAR}
           )
